import React, { useState, useContext } from 'react';
import { AppContext } from '../context/AppContext';
import { useNavigate } from 'react-router-dom';

const LoginPage = () => {
  const [isRegister, setIsRegister] = useState(false);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const { setUser } = useContext(AppContext);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    const url = isRegister ? 'http://localhost:3001/register' : 'http://localhost:3001/login';
    
    try {
      const res = await fetch(url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, password })
      });
      const data = await res.json();

      if (res.ok) {
        setUser(data); // Сохраняем юзера в контекст
        alert(isRegister ? 'Регистрация успешна!' : 'Вы вошли!');
        navigate('/'); // Уходим на главную
      } else {
        alert(data.error || 'Ошибка');
      }
    } catch (err) {
      alert('Сервер не отвечает. Запусти node server.js в папке backend!');
    }
  };

  return (
    <div style={{ padding: '20px', maxWidth: '300px', margin: 'auto' }}>
      <h2>{isRegister ? 'Регистрация' : 'Вход'}</h2>
      <form onSubmit={handleSubmit}>
        <input 
          type="text" placeholder="Логин" 
          onChange={e => setUsername(e.target.value)} 
          style={{ display: 'block', marginBottom: '10px', width: '100%' }}
        />
        <input 
          type="password" placeholder="Пароль" 
          onChange={e => setPassword(e.target.value)} 
          style={{ display: 'block', marginBottom: '10px', width: '100%' }}
        />
        <button type="submit" style={{ width: '100%' }}>
          {isRegister ? 'Создать аккаунт' : 'Войти'}
        </button>
      </form>
      <button 
        onClick={() => setIsRegister(!isRegister)} 
        style={{ marginTop: '10px', background: 'none', border: 'none', color: 'blue', cursor: 'pointer' }}
      >
        {isRegister ? 'Уже есть аккаунт? Войти' : 'Нет аккаунта? Регистрация'}
      </button>
    </div>
  );
};

export default LoginPage;
